from typing import Union, Dict

class Spreadsheet:
    def __init__(self):
        self.cells: Dict[str, Union[int, str]] = {}

    def set_cell(self, cell: str, value: Union[int, str]):
        self.cells[cell] = value

    def get_cell(self, cell: str) -> int:
        if cell not in self.cells:
            raise ValueError(f"Cell {cell} not found")

        value = self.cells[cell]
        if isinstance(value, int):
            return value
        elif isinstance(value, str) and value.startswith('='):
            formula = value[1:]
            return self.evaluate_formula(formula)
        else:
            raise ValueError(f"Invalid value in cell {cell}")

    def evaluate_formula(self, formula: str) -> int:
        formula = formula.replace(' ', '')
        for cell in self.get_referenced_cells(formula):
            formula = formula.replace(cell, str(self.get_cell(cell)))
        return eval(formula)

    def get_referenced_cells(self, formula: str) -> list:
        cells = []
        for i in range(len(formula)):
            if formula[i].isalpha():
                j = i + 1
                while j < len(formula) and formula[j].isdigit():
                    j += 1
                cells.append(formula[i:j])
                i = j - 1
        return cells

