            return self.cells[cell]
        else:
            return None

    def evaluate(self, cell):
        value = self.get_cell(cell)
        if isinstance(value, int):
            return value
        elif isinstance(value, str):
            if value.isdigit():
                return int(value)
            else:
                return self.calculate_expression(value)
        else:
            raise ValueError("Invalid cell value")

    def calculate_expression(self, expression):
        tokens = expression.split()
        result = 0
        operator = '+'
        for token in tokens:
            if token in ['+', '-', '*', '/']:
                operator = token
            elif token in self.cells:
                if operator == '+':
                    result += self.evaluate(token)
                elif operator == '-':
                    result -= self.evaluate(token)
                elif operator == '*':
                    result *= self.evaluate(token)
                elif operator == '/':
                    result /= self.evaluate(token)
            else:
                raise ValueError("Invalid token in expression")
        return result


