    def get_cell(self, cell):
        if cell in self.cells:
            return self.cells[cell]
        else:
            return None

    def evaluate(self, cell):
        if cell in self.cells:
            value = self.cells[cell]
            if isinstance(value, int):
                return value
            elif isinstance(value, str):
                if value.isdigit():
                    return int(value)
                else:
                    return self.calculate_expression(value)
            else:
                return None
        else:
            return None

    def calculate_expression(self, expression):
        parts = expression.split()
        result = 0
        operator = '+'
        for part in parts:
            if part in self.cells:
                value = self.evaluate(part)
                if value is not None:
                    if operator == '+':
                        result += value
                    elif operator == '-':
                        result -= value
                    elif operator == '*':
                        result *= value
                    elif operator == '/':
                        if value!= 0:
                            result /= value
                        else:
                            return None
                else:
                    return None
            elif part in ['+', '-', '*', '/']:
                operator = part
            elif part.isdigit():
                if operator == '+':
                    result += int(part)
                elif operator == '-':
                    result -= int(part)
                elif operator == '*':
                    result *= int(part)
                elif operator == '/':
                    if int(part)!= 0:
                        result /= int(part)
                    else:
                        return None
            else:
                return None
        return result


